Here's a complete example:

**XAML**
```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="10" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="{Binding Status}" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center"
                   VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm)
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null; // reset so the same item can be re-selected
    }
}
```

**Key binding relationships:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` | Two-way; shows/hides spinner. **You** set it to `false` when done. |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down gesture |
| `CollectionView.ItemsSource` | `Items` | `ObservableCollection` so adds/removes auto-update the UI |
| `CollectionView.SelectedItem` | `SelectedItem` | Two-way; reset to `null` after navigation so the row deselects |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires when selection changes; use this instead of event handlers |

**Important notes:**
- Set `IsRefreshing = false` in a `finally` block — if the API throws, the spinner still stops.
- Reset `SelectedItem = null` after navigating so tapping the same item again works.
- `SelectionMode="Single"` prevents multi-select; use `None` to disable selection entirely.
